const { Manifold, CrossSection, label } = api;

// =====================================================================
// PAC-MAN + GHOST diorama. Z-up, front faces -Y. ONE watertight solid.
// Pac-Man: clean yellow wedge sphere (mouth open toward -Y).
// Ghost:   domed top, straight body, classic WAVY SCALLOPED skirt,
//          white oval eyes with blue pupils (both looking -Y/left-ish).
// Both fused to a slim rounded base; pellet dots between them.
// =====================================================================

// ---------- PAC-MAN ----------
const PAC_R = 8.5;
const PAC_X = -13;
const PAC_Z = PAC_R + 0.5;            // lifted so it rests on the base

const pacSphere = Manifold.sphere(PAC_R, 64).translate([PAC_X, 0, PAC_Z]);

// Mouth wedge: triangle in XY extruded along Z, apex at Pac-Man center,
// opening toward the ghost (+X) and slightly toward the viewer (-Y) so the
// iconic open mouth reads in the 3/4 catalog view. ~33° half-angle.
const mouthHalfAngle = 33 * Math.PI / 180;
const reach = PAC_R + 3;
// Direction the mouth opens: mostly +X, a little -Y.
const dir = Math.atan2(-0.55, 1.0);            // bisector angle in XY
const a1 = dir - mouthHalfAngle;
const a2 = dir + mouthHalfAngle;
const mouthProfile = [
  [PAC_X, 0],
  [PAC_X + reach * Math.cos(a1), reach * Math.sin(a1)],
  [PAC_X + reach * Math.cos(a2), reach * Math.sin(a2)],
];
const mouthWedge = Manifold.extrude(CrossSection.ofPolygons([mouthProfile]), PAC_R * 2 + 6)
  .translate([0, 0, PAC_Z - (PAC_R + 3)]);

const pacman = label(pacSphere.subtract(mouthWedge), 'pacman');

// Pac-Man eye: a small dark dot on the upper side (so he reads as a face).
const pacEye = label(
  Manifold.sphere(0.9, 24).translate([PAC_X + 1.2, -2.0, PAC_Z + PAC_R * 0.55]),
  'paceye'
);

// ---------- GHOST ----------
const GH_X = 13;
const GH_R = 7.0;                     // body radius
const SKIRT_Z = 1.4;                  // z where the skirt teeth bottom out (base top)
const BODY_TOP = 18.5;                // top of the dome

// Dome top: a sphere whose center is placed so its top reaches BODY_TOP.
const domeC = BODY_TOP - GH_R;        // dome center z
const dome = Manifold.sphere(GH_R, 64).translate([GH_X, 0, domeC]);

// Straight body: cylinder from the hem line up into the dome (overlaps it).
// The hem (cylinder bottom) sits a few units up so the scalloped teeth hang
// below it as distinct lobes with clear concave notches between them.
const hemZ = SKIRT_Z + 4.2;
const bodyCyl = Manifold.cylinder(domeC - hemZ + 1.0, GH_R, GH_R, 64)
  .translate([GH_X, 0, hemZ]);

let ghostBody = dome.add(bodyCyl);

// Classic WAVY SCALLOPED skirt: a row of rounded teeth across the bottom.
// Each tooth is a vertical capsule (cylinder + sphere cap) hanging from the
// hem down to SKIRT_Z. They overlap the hem and each other only slightly, so
// the gaps between adjacent teeth read as the concave scallops of the hem.
const NUM_TEETH = 4;
const toothR = (GH_R * 1.06) / NUM_TEETH;        // fuller lobes, light overlap
const toothBotZ = SKIRT_Z + toothR;              // sphere cap center
const toothTopZ = hemZ + 1.2;                    // overlap up into the body
const spanHalf = GH_R - toothR;                  // spread across the full width
let teeth = null;
for (let i = 0; i < NUM_TEETH; i++) {
  const t = (i / (NUM_TEETH - 1)) * 2 - 1;       // -1..1
  const bx = GH_X + t * spanHalf;
  const col = Manifold.cylinder(toothTopZ - toothBotZ, toothR, toothR, 32)
    .translate([bx, 0, toothBotZ]);
  const cap = Manifold.sphere(toothR, 32).translate([bx, 0, toothBotZ]);
  const tooth = col.add(cap);
  teeth = teeth ? teeth.add(tooth) : tooth;
}
ghostBody = ghostBody.add(teeth);

// Flatten the very bottoms flush so the ghost sits on the base.
const cutter = Manifold.cube([GH_R * 4, GH_R * 4, 8], true)
  .translate([GH_X, 0, SKIRT_Z - 4]);
ghostBody = label(ghostBody.subtract(cutter), 'ghost');

// ---------- GHOST EYES (white ovals) + PUPILS (blue), both looking -Y/left ----------
const eyeZ = domeC + GH_R * 0.15;     // upper area, on the dome
const eyeSep = GH_R * 0.42;           // horizontal separation
const eyeFront = -(GH_R - 0.6);       // protrude from the -Y face, ~overlap

// Oval eye = a sphere scaled wider in X & taller in Z, flatter in Y.
function eyeBall(cx) {
  return Manifold.sphere(1.0, 32)
    .scale([2.0, 1.4, 2.6])
    .translate([GH_X + cx, eyeFront, eyeZ]);
}
const eyes = label(eyeBall(-eyeSep).add(eyeBall(eyeSep)), 'eyes');

// Blue pupils: small spheres set into the lower-left of each eye (looking left),
// sitting proud of the eye front (more -Y).
const pupilY = eyeFront - 1.4;        // forward of the eye
const pupilDX = -0.7;                 // shifted left (looking left)
const pupilDZ = -0.5;                 // slightly low
function pupil(cx) {
  return Manifold.sphere(0.95, 24)
    .scale([1.0, 1.2, 1.0])
    .translate([GH_X + cx + pupilDX, pupilY, eyeZ + pupilDZ]);
}
const pupils = label(pupil(-eyeSep).add(pupil(eyeSep)), 'pupils');

// ---------- PELLET DOTS between the two characters ----------
const pelletZ = 1.6;
function pellet(x) {
  return Manifold.sphere(0.85, 24).translate([x, 0, pelletZ + 0.5]);
}
const pellets = label(pellet(-3.2).add(pellet(0)).add(pellet(3.2)), 'pellets');

// ---------- SLIM ROUNDED BASE ----------
// Stadium slab = hull of two disks, one under each figure. Top at z = 1.5 so it
// overlaps the bottoms of both the ghost skirt and Pac-Man's lower cap.
const BASE_TOP = 1.5;
const BASE_BOT = -1.0;
const BASE_H = BASE_TOP - BASE_BOT;
const baseR = 10.0;
const baseDiskPac = Manifold.cylinder(BASE_H, baseR, baseR, 64).translate([PAC_X, 0, BASE_BOT]);
const baseDiskGhost = Manifold.cylinder(BASE_H, baseR, baseR, 64).translate([GH_X, 0, BASE_BOT]);
const base = label(baseDiskPac.add(baseDiskGhost).hull(), 'base');

// ---------- ASSEMBLE ----------
return base
  .add(pacman)
  .add(pacEye)
  .add(ghostBody)
  .add(eyes)
  .add(pupils)
  .add(pellets);

